import{_ as l,o as t,c as i,ag as e}from"./chunks/framework.DXGyWiRo.js";const r="/media/202507/2025-07-28_161808_1761750.31918796616843326.png",p="/media/202507/2025-07-29_110713_8207170.39811918956504566.png",o="/media/202507/2025-07-29_111355_3778940.4990959468360413.png",n="/media/202507/2025-07-29_112031_5210620.18410876200523218.png",s="/media/202507/2025-07-29_112057_2541240.3548484329154781.png",f=JSON.parse('{"title":"AIUI 应用介绍","description":"","frontmatter":{"title":"AIUI 应用介绍"},"headers":[],"relativePath":"platform-service/app-intro.md","filePath":"platform-service/app-intro.md","lastUpdated":null}'),h={name:"platform-service/app-intro.md"};function c(d,a,_,u,g,m){return t(),i("div",null,[...a[0]||(a[0]=[e('<p>背景介绍</p><p>本文档主要给开发者就目前创建的AIUI应用分类和授权方案做初步说明。</p><p>AIUI平台从2015年成立起，经过这么多年的服务更新和版本迭代，目前AIUI应用整体分两大类：</p><p>所有应用都不限制接入方式：均可按照业务实际需要对接对应链路方案的SDK或API完成能力接入。</p><h2 id="新应用-极速交互" tabindex="-1">新应用-极速交互 <a class="header-anchor" href="#新应用-极速交互" aria-label="Permalink to &quot;新应用-极速交互&quot;">​</a></h2><h3 id="_1-1-方案接入了解" tabindex="-1">1.1. 方案接入了解 <a class="header-anchor" href="#_1-1-方案接入了解" aria-label="Permalink to &quot;1.1. 方案接入了解&quot;">​</a></h3><p>👤该类应用属于AIUI最新极速超拟人交互方案绑定应用，新应用链路和授权方案固定，只能按 <a href="/sdk-dev/ultra-chain/"><strong>SDK开发接入 - 极速超拟人链路</strong></a> 或 <a href="/api-dev/ultra-chain/"><strong>API开发接入 - 极速超拟人链路</strong></a>方案接入</p><p>🔍关于极速超拟人语义服务与传统语义或通用大模型语义服务的区别，可以查看文档 <a href="/platform-service/service-chain.html"><strong>AIUI服务链路</strong></a> 详细了解方案接入。</p><h3 id="_1-2-应用说明" tabindex="-1">1.2. 应用说明 <a class="header-anchor" href="#_1-2-应用说明" aria-label="Permalink to &quot;1.2. 应用说明&quot;">​</a></h3><p>极速交互类型，应用区分方式主要可以分为一下几点：</p><p><strong>- 创建时间</strong></p><p>从2025-06-12后创建的所有应用都属于极速交互类应用。</p><p><strong>- 应用配置</strong></p><p>应用下语义和大模型配置在服务链路中固定开启，不支持开发者自定义开关；另外新增基础配置设置，支持开发者进行识别引擎、兜底大模型、回复角色选配。</p><p><img src="'+r+'" alt="" title="null"></p><h3 id="_1-3-授权说明" tabindex="-1">1.3. 授权说明 <a class="header-anchor" href="#_1-3-授权说明" aria-label="Permalink to &quot;1.3. 授权说明&quot;">​</a></h3><p>极速交互类应用，平台给与开发者的免费授权信息如下：</p><ul><li>免费服务包：10000 次 有效期1年（从应用创建时计算）</li><li>默认API并发路数：3路</li><li>免费AIUI装机量：20台</li><li>免费唤醒（VTN）装机量：20台</li></ul><p><a href="/faq/contact.html">如需提升服务授权可以联系我们&gt;&gt;&gt;</a></p><h2 id="老应用" tabindex="-1">老应用 <a class="header-anchor" href="#老应用" aria-label="Permalink to &quot;老应用&quot;">​</a></h2><h3 id="_2-1-方案接入了解" tabindex="-1">2.1. 方案接入了解 <a class="header-anchor" href="#_2-1-方案接入了解" aria-label="Permalink to &quot;2.1. 方案接入了解&quot;">​</a></h3><p>老应用按照配置不同，服务提供两种交互链路配置选型，分别为：</p><p><strong>- 传统语义链路</strong></p><p>按 <a href="/sdk-dev/classic-chain/"><strong>SDK开发接入 - 传统语义链路</strong></a> 或 <a href="/api-dev/classic-chain/"><strong>API开发接入 - 传统语义链路</strong></a>方案接入</p><p><strong>- 通用大模型链路</strong></p><p>按 <a href="/sdk-dev/llm-chain/"><strong>SDK开发接入 - 通用大模型链路</strong></a> 或 <a href="/api-dev/llm-chain/"><strong>API开发接入 - 通用大模型链路</strong></a>方案接入</p><p>关于传统语义和通用大模型语义服务与极速超拟人服务的区别，可以查看文档<a href="/platform-service/service-chain.html" title="AIUI服务链路">AIUI服务链路</a>详细了解。</p><h3 id="_2-2-应用说明" tabindex="-1">2.2. 应用说明 <a class="header-anchor" href="#_2-2-应用说明" aria-label="Permalink to &quot;2.2. 应用说明&quot;">​</a></h3><p>老应用按时间周期也分两大类：</p><ul><li>传统语义链路和通用大模型链路都支持</li><li>仅支持传统语义链路 下面就两种不同应用做详细说明。</li></ul><h4 id="_2-2-1-传统和大模型都支持的" tabindex="-1">2.2.1. 传统和大模型都支持的 <a class="header-anchor" href="#_2-2-1-传统和大模型都支持的" aria-label="Permalink to &quot;2.2.1. 传统和大模型都支持的&quot;">​</a></h4><p>该类应用是AIUI服务升级中间版本，开发者可以通过大模型开关来配置选择对应的服务链路：</p><ul><li>大模型：开 服务指向到通用大模型语义链路</li><li>大模型：关 服务指向到传统语义链路。</li></ul><p><img src="'+p+'" alt="" title="null"></p><p>应用区分方式：</p><ul><li>创建时间 从 <strong>2022-06-01</strong> 到 <strong>2025-06-11</strong> 时间周期内创建的所有应用。</li><li>功能模块 传统语义、大模型、合成、后处理都支持模块化开关选配</li><li>应用信息 应用右上角支持appid、appkey和apiserce信息查询</li></ul><p><img src="'+o+'" alt="" title="null"></p><h4 id="_2-2-2-仅支持传统语义链路的" tabindex="-1">2.2.2. 仅支持传统语义链路的 <a class="header-anchor" href="#_2-2-2-仅支持传统语义链路的" aria-label="Permalink to &quot;2.2.2. 仅支持传统语义链路的&quot;">​</a></h4><p>该类应用是AIUI最早应用版本，由于缺少秘钥信息应用不支持开启大模型，仅可以做传统语义方案对接。应用区分方式为：</p><ul><li>创建时间 至 <strong>2022-06-01</strong> 时间之前创建的所有应用。</li><li>功能模块 <ul><li>传统语义、合成、后处理都支持模块化开关选配</li><li>不支持大模型配置(开启会有协议不兼容提示)</li></ul></li><li>应用信息 仅提供appid和appkey，没有apisecret信息</li></ul><p><img src="'+n+'" alt="" title="null"></p><p><img src="'+s+'" alt="" title="null"></p><h3 id="_2-3-授权说明" tabindex="-1">2.3. 授权说明 <a class="header-anchor" href="#_2-3-授权说明" aria-label="Permalink to &quot;2.3. 授权说明&quot;">​</a></h3><p>通用类应用，平台给与开发者的免费授权信息如下：</p><h3 id="注意" tabindex="-1">注意： <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意：&quot;">​</a></h3><p>AIUI和唤醒装机量统计不区分服务链路，两者共同消耗。建议开发者一个应用固定选用一种服务链路，避免后续装机量授权统计区分困难。</p><ul><li>传统语义服务： <ul><li>免费日服务包：普通版 500次</li><li>默认API并发限制：20qps</li><li>免费AIUI装机量：20台</li><li>免费唤醒（VTN）装机量：20台</li></ul></li><li>通用大模型服务 <ul><li>免费日服务包：大模型版 500次</li><li>默认API并发限制：20qps</li><li>免费AIUI装机量：20台</li><li>免费唤醒（VTN）装机量：20台</li></ul></li></ul><p><a href="/faq/contact.html">如需提升服务授权可以联系我们&gt;&gt;&gt;</a></p>',48)])])}const q=l(h,[["render",c]]);export{f as __pageData,q as default};
